var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"이면세계 심도 5 – 07:05:23\\n강습함 코핀, 코핀 컴퍼니 <color=#ffd34c>브리핑 중</color>\\nCSE Lv. <b>1</b>","JPN":"裏世界深度5 – 07:05:23\\n強襲艦コフィン、コフィンカンパニー<color=#ffd34c>ブリーフィング中</color>\\nCSE Lv.<b>1</b>","ENG":"Counterside Depth 5 – 07:05:23\\nAssault Ship Coffin, Coffin Company<color=#ffd34c>Briefing</color>\\nCSE Lv. <b>1</b>","TWN":"異界深度 5 – 07:05:23\\n強襲艦，科芬公司<color=#ffd34c>簡報中</color>\\nCSE Lv. <b>1</b>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"……그래서 우린 지금 어디 가는 거야?","JPN":"……それで、私たちいまどこに向かっているの？","ENG":"So... Where are we going right now?","TWN":"……所以我們現在要去哪裡？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"현재 우리는 오비탈 베이스를 추격 중입니다. ","JPN":"現在私たちはオービタルベースを追撃中です。 ","ENG":"We’re currently in pursuit of the Orbital Base.","TWN":"我們正在追蹤軌道基地。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"알파트릭스 그룹이 운용하는 이동형 자율 생산 공장이죠.","JPN":"アルファトリックスグループが運用する移動型自律生産工場ですね。","ENG":"It’s a mobile production facility operated by the Alphatrix group.","TWN":"也就是阿爾法崔克斯集團操控的移動型自動生產工廠。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"지금 그걸 묻는 게 아니잖아.","JPN":"今はそんなこと聞いてるんじゃないでしょ。","ENG":"That wasn’t my question.","TWN":"我不是在問這個！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"지난번 선배가 납치된 뒤로……","JPN":"この前先輩がさらわれてから……","ENG":"After Shiyoon was kidnapped last time...","TWN":"自從上次前輩被綁架後……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아니, 레이 선배가 사라진 뒤로 뭔가가 빠르게 바뀌고 있어.","JPN":"ううん、レイ先輩がいなくなってから何かが急速に変わってきてる。","ENG":"No, after Ray disappeared, everything has been changing quickly.","TWN":"不是，是自從雷伊前輩消失後，總覺得有什麼正在快速變化中。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"부사장님도 그렇고 소대장도 분명히 분위기가 달라졌다고.","JPN":"副社長もそうだし、小隊長も確かに雰囲気が変わってるよ。","ENG":"Vice President, you and the Commander have been giving off very different vibes than usual.","TWN":"很明顯副總和小隊長的感覺都變得不太一樣。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"어차피 싸워야 한다면 무슨 사정인지는 알려 줘야 하지 않아?","JPN":"どうせ戦わなくちゃならないなら、どんな事情かは教えてくれてもいいんじゃない？","ENG":"If we have to fight, shouldn’t you at least tell us what’s going on?","TWN":"就算要打也要知道為何而打吧？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"……세상에는 안다고 해서 바꿀 수 없는 것도 있습니다.","JPN":"……世の中には知っていても変えられないものがあるのです。","ENG":"...There are some things in this world that you cannot change, even if you are aware of them.","TWN":"……很多事就算知道也無法改變。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L14_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"애초에 스승님께는 별 말도 못하면서 저에게는 자꾸 떼를 쓰는군요.","JPN":"そもそも、師匠には何も言えないくせに私にはよくわがままを言うのですね。","ENG":"You tend to complain to me while being unable to bring this up with Master.","TWN":"你對著師父連吭都不敢吭一聲，倒是很會跟我吵嘛。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L15_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"혹시 제가 만만하신가요, 미나 양?","JPN":"もしかして、私が甘く見えますか、ミナさん？","ENG":"Am I a joke to you, Mina?","TWN":"米娜，你是看我好欺負嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그, 그런 뜻이 아니잖아.","JPN":"そ、そういう意味じゃないでしょ。","ENG":"Y-you know that’s not what I’m implying!","TWN":"我…我沒這個意思！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그냥…… 이젠 그 허신인가 뭔가 하는 괴물도 쓰러트렸으니까.","JPN":"ただ……もうその虚神とかいう怪物も倒したんだし。","ENG":"It’s just that... I even defeated that monster called the Hollow God or something.","TWN":"我只是覺得……現在的我足以打倒那個叫幻神還是什麼的怪物，"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"나도 그렇게 약하고 보호만 받을 실력은 아니라는 거야.","JPN":"私も弱くて保護されなきゃならない実力じゃないってことよ。","ENG":"What I’m trying to say is that I’m not weak, and you don’t need to protect me.","TWN":"就證明我不是溫室裡的花朵，只能被保護。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그런 걸 바로 기적 같은 일이라고 하는 거다.","JPN":"そういうのを奇跡みたいな事っていうんだ。","ENG":"That’s exactly what you call a miracle.","TWN":"那只能說是奇蹟。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그 괴물을 상대로 네가 살아남은 건 첫째로 운이 좋아서였고, 둘째로 그 대령이라는 녀석이 마침 같이 있어서였어.","JPN":"あの怪物を相手にお前が生き残れたのは、運が良かったということと、大佐だとかいう奴がちょうど一緒にいたからだ。","ENG":"The first reason you were able to fight that monster and live to tell the tale is because you were lucky. The second reason is because the colonel was there with you.","TWN":"面對那個怪物，你之所以還能活著，第一是因為你運氣好，第二是因為那個上校正好也在。"},"stage":{"bg":"MAINSTREAM_805","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그걸 자기 실력이라고 착각하지 마라. 그 순간 돌아오지 못할 테니까.","JPN":"それを自身の実力だと誤解するな。誤解した瞬間、戻れなくなるぞ。","ENG":"Don’t delude yourself into thinking that it was your skills that saved you. That kind of luck won’t come again.","TWN":"不要誤會是你能力好，那只是一次的幸運。"},"stage":{"bg":"MAINSTREAM_805","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"……그렇게 말하지 않아도 내 실력은 내가 잘 알고 있어.","JPN":"……そんな風に言わなくたって自分の実力はよくわかってる。","ENG":"...You don’t need to put it like that. I know my limits.","TWN":"……不用你說我也很清楚自己的能力到哪裡。"},"stage":{"bg":"MAINSTREAM_805","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"하지만 이렇게 계속 비밀로 할 거면 대체 난 왜 데리고 온 거야?","JPN":"でも、こうやってずっと秘密にするつもりなら、なんで私なんかを連れてきたの？","ENG":"But if you’re going to keep me in the dark like this, why did you even bring me along in the first place?","TWN":"只是你們堅持不告訴我的話，又為什麼要帶上我？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"이제부터 네게 안전한 곳은 세상 어디에도 없기 때문이다.","JPN":"これからお前にとって安全な場所は、この世のどこにもなくなった。","ENG":"Because you are no longer safe anywhere in the world.","TWN":"因為對你而言，現在已經沒有任何地方是安全的。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"어차피 위험을 감수해야 한다면 내 곁에 있는 편이 그나마 낫겠지.","JPN":"どうせ危険を甘受せねばならないなら、私の傍にいた方がまだいいだろう。","ENG":"If danger lurks around every corner, you might as well be close to me.","TWN":"既然都有危險，那不如就待在我身邊吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"<color=#ffd34c>네게</color> 안전한 곳이라……","JPN":"<color=#ffd34c>お前にとって</color>安全な場所か……","ENG":"A safe place for <color=#ffd34c>you</color>, eh?","TWN":"<color=#ffd34c>對你而言</color>安全的地方……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그러면 전 딱히 아무 곳에나 있어도 안전하다는 뜻이겠네요.","JPN":"それでは、僕はどこにいても安全ということですね。","ENG":"Then I’ll probably be safe regardless of where I am.","TWN":"意思就是，不管我在哪裡都很安全囉？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"저도 그 기사님들과는 꽤 마찰이 있었는데 별말 없으신 걸 보면……","JPN":"僕もその騎士さんたちと結構揉めていたのに、何も言われないところをみると……","ENG":"I also have quite a history with those knights, but seeing that you aren’t saying much about me...","TWN":"我也有和那些騎士發生過一些衝突，但師父什麼話都沒說……"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"역시 미나 양은 스승님뿐 아니라 그 마왕의 일당이라는 분들께도 특별한 존재인가 보죠?","JPN":"やっぱりミナさんは、師匠だけでなく、その魔王の一味という方たちにとっても特別な存在なんでしょうね？","ENG":"That must mean Mina is special not just to you, Master, but also to those serving the Demon Lords.","TWN":"就表示米娜對師父，或對那個魔王的黨羽而言，都是很特別的囉？"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"쓸데없이 넘겨짚지 마라. 난 그저 소대장으로서의 의무를 말했을 뿐이야.","JPN":"無駄な憶測はするな。私はただ小隊長としての義務を話しただけだ。","ENG":"Don’t make baseless assumptions. I’m merely stating my responsibility as Commander.","TWN":"不要自己胡亂臆測，我只是在盡小隊長的義務而已。"},"stage":{"bg":"MAINSTREAM_7040010","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하하, 그야 물론이죠.","JPN":"ハハ、もちろんです。","ENG":"Haha, of course I won’t.","TWN":"哈哈，師父說的是。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하지만 제 6종, 신이라 불리는 침식체조차 쓰러트린 미나 양이 위험할 정도라면……","JPN":"でも、第6種、神と呼ばれる侵食体さえ倒してしまった、ミナさんが危険なくらいなら……","ENG":"But, if Mina is in danger... And she actually defeated a Category 6 C.O. that was considered a god...","TWN":"不過那個6類，可是稱之為神的侵蝕體，連打倒它的米娜都有危險的話……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그 황태자라는 분, 그리고 그 뒤에 계시는 마왕이라는 분은 대체 얼마나 강한 걸까요?","JPN":"その皇太子様と、背後にいらっしゃる魔王様はいったいどれくらい強いんでしょうね？","ENG":"I can only imagine how strong that guy called the Crown Prince and the Demon Lord commanding him are.","TWN":"那那個皇太子和在幕後的魔王究竟有多強？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"주시윤, 넌 강해졌다.","JPN":"シリュウ、お前は強くなった。","ENG":"Joo Shiyoon, you’re stronger than you were then.","TWN":"周時雲，你變強了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"네……?","JPN":"はい……？","ENG":"Hmm..?","TWN":"蛤……？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"연화를 찾은 시점에서, 넌 내가 이전에 만났던 강력한 카운터들 중에서도 손에 꼽힐 만한 힘을 가졌어.","JPN":"蓮華を見つけた時点で、お前は私がこれまでに会った強いカウンターの中でも指折りの力を手にした。","ENG":"Ever since you found Yeonhwa, you’ve amassed extraordinary power, even among the many notable Counters I have met up to this point.","TWN":"自從找到蓮華後，你的實力在我遇過的高手制裁者之中，也是屈指可數的。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"마음에 들진 않지만 그게 사실이지.","JPN":"気にくわないが事実は事実だ。","ENG":"I don’t like it, but that’s the truth.","TWN":"雖然我不想承認，但這是事實。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하하, 갑자기 칭찬하시니까 쑥쓰러운데요.","JPN":"ハハ、突然褒められると照れますね。","ENG":"Haha, your sudden compliment is making me blush.","TWN":"哈哈，師父怎麼突然稱讚我，害我有點害羞。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"하지만 분명히 말해 두마.","JPN":"だが、はっきりと言っておく。","ENG":"However, I’ll make this very clear.","TWN":"不過我要清楚地告訴你，"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"혹시라도 마왕과 마주친다면, 도망쳐라.","JPN":"万が一、魔王と出くわすことがあれば、逃げろ。","ENG":"Should you encounter a Demon Lord, run.","TWN":"若是你遇上魔王，就逃吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그게 내가 소대장으로서 네게 할 수 있는 현실적인 충고다.","JPN":"これが私が小隊長としてお前にできる現実的な忠告だ。","ENG":"That is the most practical advice that I can give as your Commander.","TWN":"那是我身為小隊長，唯一能夠給你的忠告。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"……그러면 미나 양은요?","JPN":"……ではミナさんは？","ENG":"...What about Mina?","TWN":"……那米娜呢？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"신입의 경우에는…… 그때 내가 곁에 있고, 전처럼 운이 좋기만을 빌어야겠지.","JPN":"新人の場合は……その時私が側にいて、以前のように運が良いことを祈るしかないな。","ENG":"As for the rookie... We can only hope that I’ll be with her, and that luck will be with her like last time.","TWN":"新人的話……到時我會跟她一起，然後祈禱能夠跟上次一樣幸運。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"상대가 마왕이라면 신입이 도망가도록 놔두지 않을 거다.","JPN":"相手が魔王なら新人が逃げるのを黙って見てはいまい。","ENG":"If the opponent is a Demon Lord, it will not allow the rookie to escape.","TWN":"若對手是魔王，她是不可能讓新人就這樣逃走的。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"주시윤, 네 말처럼 신입은 놈들에게도 특별한 존재가 맞으니까.","JPN":"シリュウの言葉どおり、新人はやつらにとって特別な存在には違いないからな。","ENG":"Just as you said, Joo Shiyoon, the rookie is special to them as well.","TWN":"畢竟就像你說的，新人對那些傢伙而言也是很特別的。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"자, 자. 다들 긴장 풀어요. 얼굴이 완전히 굳었잖아요?","JPN":"さあ、さあ。皆さん緊張を解いて。顔が固まってますよ？","ENG":"There there, everyone relaxes. What’s with all the stern faces?","TWN":"好了好了，大家放輕鬆點，大家的表情未免也太僵硬。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_CLAP"},{"id":"L19_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그나저나 고등학교 동창이랑 직장 동료도 모자라서 이제는 마왕님들에게도 찍히다니.","JPN":"それにしても、高校の同窓や職場の仲間では飽き足らず、今や魔王様にも狙われるとはね。","ENG":"On another note, first targeted by your high school classmate, then your colleague, and now the Demon Lords.","TWN":"不只被高中同學和公司同事盯上，現在連魔王也來湊一腳，"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"역시 우리 미나는 대단해. 인기 많아서 좋겠네.","JPN":"やっぱりミナさんはすごい。モテモテでいいわね。","ENG":"You can’t seem to catch a break, Mina. It must be nice being popular.","TWN":"我們米娜果然厲害，人氣有夠旺的，真好！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"야, 넌 이런 상황에도 농담이 나와?","JPN":"ちょっと、冗談なんて言える状況？","ENG":"Hey, how can you joke in this situation?","TWN":"喂，這種時候你還有心情說笑嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"뭐 어때. 내 일도 아닌데.","JPN":"いいじゃない。私のことじゃないし。","ENG":"What about it? I’m not the one being targeted.","TWN":"不然咧？反正又不甘我的事。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아니, 그게 무슨……","JPN":"はあ、何よそれ……","ENG":"What...? You've got to be─","TWN":"你在說什麼……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그리고 너도, 걱정한다고 해결되는 게 아니잖아?","JPN":"それにあなたが心配したからってどうにかなる問題じゃないでしょ？","ENG":"Also, you need to calm down. It’s not like fretting about it will solve anything.","TWN":"再說，就算你擔心也無法解決事情吧？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"부사장님도, 소대장님도 다 생각이 있으니까 그러시는 거겠지.","JPN":"副社長も小隊長もなにか考えがあるからそうなんだろうし。","ENG":"I’m pretty sure the Vice President and the Commander know what they’re doing.","TWN":"副總和小隊長會那麼說，肯定是有她們自己的想法吧？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"해결책이 없을 때는 마음이라도 편히 먹는 게 이득이라는 거야.","JPN":"解決策がない時は気持ちだけでも楽に持っておくのが得ってものよ。","ENG":"All I'm saying is that if there isn't a solution, being at ease is the best course of action.","TWN":"既然沒有解決辦法，那就放寬心吧～"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L27_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L28_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"정말…… 속 편한 입장이라 좋겠다.","JPN":"本当に……気楽な立場でいいわね。","ENG":"I... envy you for having the luxury of being laid back.","TWN":"真羨慕你……可以說得那麼輕鬆。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L30_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"……저도 조금 놀랐군요.","JPN":"……私も少し驚きました。","ENG":"...To be honest, I’m also surprised a bit.","TWN":"……我也有點意外呢。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"서윤 양이 절 그렇게 믿어주실 줄은 몰랐습니다만?","JPN":"シズカさんがそれほど私を信じてくれているとはね？","ENG":"I never expected Seo Yoon to trust me that much.","TWN":"沒想到徐芸你這麼信任我們？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"네? 전혀 안 믿고 있는데요?","JPN":"え？　まったく信じていませんけど？","ENG":"Hmm? It’s not you that I trust.","TWN":"嗯？我不是信任你們欸？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"제가 믿고 있는 건 사장님이거든요.","JPN":"私が信じているのは社長ですから。","ENG":"I trust Boss.","TWN":"我是信任老闆。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"원래 줄을 타도 1인자에게 타야 하는 거 아니겠어요?","JPN":"派閥に入るんだったら第一人者のところじゃないですか？","ENG":"After all, shouldn’t I place my bets on the winning horse?","TWN":"要找靠山的話當然要找靠得住的囉？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"부사장 라인처럼 낡은 동아줄을 제가 잡을 리가 있나요.","JPN":"副社長のラインみたいに時代遅れの派閥に私が入ると思いますか？","ENG":"There’s no way that I would bet on wash-outs like you, Vice President.","TWN":"誰會找像副總這種靠不住的？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"……아, 네. 물론 그렇겠죠.","JPN":"あ……ええ。そうでしょうね。","ENG":"Ah, of course you didn’t.","TWN":"……嗯，對，你說得沒錯。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"혹시 다른 누군가로 바꿔치기 당했나 싶었는데 아닌 것 같아 다행이군요.","JPN":"他の誰かと変わったのかと思ったけど、違ったみたいでよかったです。","ENG":"I was worried that someone had switched bodies with you, but thankfully that’s not the case.","TWN":"我還以為你被誰洗腦呢，沒有就好。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그럼 얼른 가볼까요? 오비탈 베이스로.","JPN":"それじゃ、さっそく行きますか？　オービタルベースに。","ENG":"So, shall we get going to Orbital Base?","TWN":"那就趕快出發去軌道基地吧？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L41_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"묘하게 들떠 보이네, 너. 왜 그렇게 적극적으로 움직이는 거야?","JPN":"妙にそわそわしてるね、あんた。なんでそんなに積極的なの？","ENG":"You seem strangely excited. Why are you so eager about this mission?","TWN":"你怎麼好像異常興奮？是在積極個什麼勁兒？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L42_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"흐흥, 내가 맡은 일 대충 하는 거 본 적 있어?","JPN":"ふふん、私が任された仕事を適当にやったことがある？","ENG":"Hehe, have you ever seen me slack off at work?","TWN":"呵呵，你有看我做事草率過嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그거야 뭐…….","JPN":"そりゃあ……","ENG":"Well, no...","TWN":"這倒是……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"거기다 사장님께서 따로 약속해 주셨거든.","JPN":"それに、社長が約束してくれたの。","ENG":"Also, Boss made a separate promise to me.","TWN":"而且老闆有另外答應我，"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"이번 작전만 잘 끝내면 우리 알트 소대가 더 강해질 수 있는 선물을 주신다고 말이야.","JPN":"今度の作戦さえうまくやり遂げれば、アルト小隊がもっと強くなれるものをくれるってね。","ENG":"He promised to give us a gift that will make ALT Squad stronger should we finish this mission well.","TWN":"等這次作戰結束後，他會送個可以讓我們阿爾特小隊變得更強的禮物。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭐? 너 그 이상한 창을 가지고도 부족한 거야?","JPN":"え？　その変な槍じゃあ足りないっていうの？","ENG":"Huh? That weird spear isn’t enough for you?","TWN":"什麼？你都已經有那把奇怪的槍還不滿足嗎？"},"stage":{"bg":"MAINSTREAM_5302011","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"이번엔 또 무슨 일을 꾸미려고……?","JPN":"今度はまた何を企んでいるのやら……","ENG":"What are you up to now...?","TWN":"你又想幹嘛……？"},"stage":{"bg":"MAINSTREAM_5302011","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"괜한 걱정 하지 마. 네가 생각하는 그런 건 아니니까.","JPN":"つまらない心配しないで。あなたの考えとは違うから。","ENG":"Don’t worry, it’s not what you think.","TWN":"放心，不是你想的那樣。"},"stage":{"bg":"MAINSTREAM_5302011","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"하지만 우린 누구처럼 비밀스런 잠재력이나 괴물 소대장이나 일편단심 챙겨주는 선배 같은 게 없어서 말이야.","JPN":"だけど、私たちには誰かさんみたいに隠された潜在能力とか、怪物小隊長とか、一途に面倒を見てくれる先輩みたいな人がいないの。","ENG":"However, unlike someone, we don’t have secret powers, a badass commander or a devoted senior looking after us.","TWN":"只是我們隊裡的人又不像某人有神秘的潛能，也沒有怪物小隊長，更沒有忠心耿耿的前輩嘛。"},"stage":{"bg":"MAINSTREAM_5302011","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"우릴 챙겨줄 건 우리밖에 없어. 그러니까 기회가 오면 놓치지 말고 잡는 것뿐이야.","JPN":"自分たちの面倒を見れるのは自分たちだけ。だから機会があれば逃さずに掴むだけよ。","ENG":"Only we need to look after ourselves. That’s why we're trying to grab every opportunity I can.","TWN":"我們就只能靠自己，現在有機會當然要抓緊囉。"},"stage":{"bg":"MAINSTREAM_5302011","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MAINSTREAM_5302011","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"부사장님, 조금 전에 오비탈 베이스가 관측됐습니다!","JPN":"副社長、少し前にオービタルベースが観測されました！","ENG":"Vice President, the Orbital Base has been spotted just now!","TWN":"副總,，剛才觀測到軌道基地！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L10_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"역시 정령님의 양자 천리안. 이면세계의 목표도 피해 갈 수 없죠.","JPN":"やはり精霊様の量子千里眼。裏世界の目標も避けて通ることはできません。","ENG":"The guardian spirit’s All-Seeing Quantum Eye never fails to impress me. Even the machinations of the Counterside cannot stay hidden from it.","TWN":"精靈大人的量子千里眼果然厲害，異界的目標也逃不過它的法眼呢。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"항상 감사하세요, 레나 양.","JPN":"いつも感謝しなさい、レナ。","ENG":"Thank you as always, Lena.","TWN":"蕾娜，要常常心懷感激知道嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"정령님이 아니라 알파트릭스 회장님이 전송해 준 좌표로 온 것뿐이잖아.","JPN":"精霊様ではなくて、アルファトリックス会長が送ってくれた座標に来ただけじゃない。","ENG":"However, we merely came to the coordinates sent to us by the President of Alphatrix, not the guardian spirit.","TWN":"才不是什麼精靈大人，是阿爾法崔克斯會長把座標傳過來的。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"그리고 점성술이나 천리안이나 하나만 해 줄래? 항해 기록 쓸 때 골치 아프거든?","JPN":"それに、占星術でも千里眼でもひとつだけにしてくれる？　航海記録をつける時に困るんだから。","ENG":"Also, make up your mind whether we found it through astrology or an all-seeing eye. It’s a pain in the butt when writing down the navigation logs.","TWN":"還有，看你是要用占星術還是千里眼，選一個好嗎？不然我的航行紀錄很難寫欸！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"……이 불신자.","JPN":"……不届き者。","ENG":"...Shun the non-believer.","TWN":"……你這個不信的人！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L15_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"아아, 점괘에 따르면 레나 양이 출항할 때 몰래 맥주를 숨겨왔더라. 장소는 왼쪽 캐비닛……","JPN":"ああ、占いによるとレナが出港する時にこっそりビールを隠し持ってきたって。場所は左のキャビネット……","ENG":"Ahh, according to my divination, Lena hid beer on the ship when we left port. It’s hidden in the left cabinet...","TWN":"喔喔～根據占卜的結果，蕾娜出發時有偷藏啤酒，就在左邊櫃子裡……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L16_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":" 읍읍!","JPN":" んぐっ！","ENG":" Mmff! Mff!","TWN":"喔喔！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"쉿! 쉬잇!","JPN":"シッ、シッ！","ENG":"Shh! Shush!","TWN":"噓！別那麼大聲！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"레나 양의 작전 규칙 위반 건은 나중에 처리하죠. 다들 출격준비 하세요.","JPN":"レナさんの作戦規定違反の件は後で処理します。皆さん、出撃準備をお願いします。","ENG":"We’ll discuss Lena’s violation of operational regulations later. Everyone, prepare for deployment.","TWN":"蕾娜違反作戰守則一事之後再處理，大家先預備出擊！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"오비탈 베이스를 점거 중인 침식체들은 펜릴 소대에 맡기겠습니다.","JPN":"オービタルベースを占拠中の侵食体はフェンリル小隊にお任せします。","ENG":"We’ll leave the Corrupted Objects occupying the Orbital Base to Fenrir Squad.","TWN":"佔據軌道基地的侵蝕體就交給芬里爾小隊負責，"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"알트 소대는 그 사이에 관제실로 가서 회장님의 신변을 확보하세요.","JPN":"アルト小隊はその間、管制室に向かい会長の身辺の安全を確保してください。","ENG":"In the meantime, ALT Squad is to head to the control room and secure the President.","TWN":"阿爾特小隊就趁機到控制室確認會長的安危。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"회장님의 안전이 확보되면 남은 침식체들을 처리하고 오비탈 베이스의 기능을 정상으로 되돌릴 겁니다.","JPN":"会長の安全が確保されたら、残りの侵食体を処理し、オービタルベースの機能を正常に戻します。","ENG":"Once the President's safety has been secured, we will clean up the remaining C.O.s and restore the Orbital Base’s functions.","TWN":"確保會長安全無疑後，再去處理其餘的侵蝕體，然後讓軌道基地的功能恢復正常運作。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"아, 혹시나 해서 말씀드리지만 오비탈 베이스에 생채기 하나 나지 않게 조심하세요.","JPN":"あ、念のため言っておきますが、オービタルベースに傷一つでもつけないように気をつけてください。","ENG":"Oh, also, make sure that you don’t leave a single scratch on the Orbital Base.","TWN":"對了，我提醒一下，請千萬小心不要傷到軌道基地。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"국가 수준에서도 소유하지 못할 만큼 비싼, 아~주 비싼 함선이니까요.","JPN":"国家レベルでも保有できないくらい高価な、と～っても高価な艦船ですからね。","ENG":"It’s an extremely expensive ship that not even a country can afford one.","TWN":"那艘艦船可是貴到連一個國家的資產也買不起，非～～常昂貴。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"배상 청구가 들어오는 날에는 평생 무급으로 일하게 만들어 드리겠습니다.","JPN":"賠償請求が来た場合は、一生お給料なしで勤務してもらいます。","ENG":"The day we receive an invoice for repairs is the day you start working for free for the rest of your lives.","TWN":"若是有人向我要求賠償，那我只好讓你們永遠做白工囉。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"……그놈의 돈 얘기는 빼먹지를 않는군.","JPN":"……いつも金の話だけは忘れないんだな。","ENG":"...She never stops mentioning money.","TWN":"……她真是隨時隨地都想到錢呢。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L30_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"3분 뒤, 전원 강하 준비를 마치고 램프도어 앞으로 집결한다. 이상.","JPN":"3分後に全員降下準備を終え、ランプドア前に終結する。以上。","ENG":"All hands prepare for drop and gather at the ramp door in 3 minutes. Let’s move.","TWN":"3分鐘後，全員做好降落準備後，在門前集合，以上。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};